// The schema this exercise runs against.
// npx prisma db push && npx prisma generate
generator client {
  provider = "prisma-client-js"
  output   = "./generated"
}

datasource db {
  provider = "postgresql"
  url      = "postgresql://postgres:x@localhost:55432/prisma_codelab"
}

enum Role {
  USER
  ADMIN
}

model User {
  id    Int     @id @default(autoincrement())
  email String  @unique
  name  String?
  age   Int?
  role  Role    @default(USER)
  posts Post[]
}

model Post {
  id        Int      @id @default(autoincrement())
  title     String
  published Boolean  @default(false)
  views     Int      @default(0)
  authorId  Int
  author    User     @relation(fields: [authorId], references: [id])
}

// Run once before the exercise: npx tsx seed.ts
import { PrismaClient } from './generated';
const prisma = new PrismaClient();

async function main(){
await prisma.post.deleteMany(); await prisma.user.deleteMany();
const ann = await prisma.user.create({ data: { email: "ann@x.io", name: "Ann", age: 30 } });
const bob = await prisma.user.create({ data: { email: "bob@x.io", name: "Bob", age: 25 } });
await prisma.user.create({ data: { email: "cy@x.io", name: "Cy" } });
await prisma.post.createMany({ data: [
  { title: "Intro to SQL",    published: true,  views: 100, authorId: ann.id },
  { title: "Prisma Basics",   published: true,  views: 250, authorId: ann.id },
  { title: "Draft on Prisma", published: false, views: 0,   authorId: ann.id },
  { title: "Redis Notes",     published: true,  views: 80,  authorId: bob.id },
  { title: "Mongo Guide",     published: true,  views: 150, authorId: bob.id },
  { title: "SQL Advanced",    published: false, views: 20,  authorId: bob.id },
]});
}
main().finally(()=>prisma.$disconnect());

